import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { WheelModuleParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/WheelModuleParser';

export class WheelModuleEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, WheelModuleParser);
        console.log('[🎡] WheelModuleEvent wired.');
    }

    public getParser(): WheelModuleParser {
        return this.parser as WheelModuleParser;
    }
}
